#include <stdio.h>
#include <string.h>
#include <time.h>

typedef struct Transaction {
 char sender[256];
 char receiver[256];
 int amount;
 time_t timestamp;
 char signature[256];
} Transaction;

void sign_transaction(Transaction* transaction, char* private_key) {
 // Simulate signing with private key
 strcpy(transaction->signature, "signature");
}

int validate_transaction(Transaction* transaction) {
 // Simulate validation
 return 1;
}

typedef struct Node {
 Transaction* mempool[10];
 int mempool_size;
} Node;

void add_transaction(Node* node, Transaction* transaction) {
 node->mempool[node->mempool_size++] = transaction;
}

void mine_block(Node* node) {
 // Simulate mining a block
 printf("Block mined\n");
}

int main() {
 // Create a transaction
 Transaction transaction;
 strcpy(transaction.sender, "Alice");
 strcpy(transaction.receiver, "Bob");
 transaction.amount = 10;
 transaction.timestamp = time(NULL);
 sign_transaction(&transaction, "private_key");

 // Create a node
 Node node;
 node.mempool_size = 0;
 add_transaction(&node, &transaction);

 // Mine a block
 mine_block(&node);

 // Simulate subsequent confirmations
 for (int i = 0; i < 6; i++) {
 printf("Confirmation %d\n", i+1);
 }
 return 0;
}
